\usetikzlibrary{arrows.meta}
\begin{tikzpicture}[scale=1.5]
  % Two perpendicular rays forming a 90-degree angle
  \draw[very thick, -{Stealth[length=3mm]}] (0,0) -- (4,0);
  \draw[very thick, -{Stealth[length=3mm]}] (0,0) -- (0,4);

  % Right angle square symbol
  \draw[thick, blue] (0.4,0) -- (0.4,0.4) -- (0,0.4);

  % Angle label
  \node[blue, font=\large, fill=white, inner sep=2pt] at (0.8,0.8) {$90^{\circ}$};

  % Vertex label
  \node[below left=4pt, font=\normalsize] at (0,0) {A};

  % Ray labels
  \node[below=4pt, font=\normalsize] at (4,0) {B};
  \node[left=4pt, font=\normalsize] at (0,4) {C};

  % Vertex dot
  \fill (0,0) circle (0.05);

  % Classification label
  \node[below=1.0cm, font=\large] at (2, 0) {Right angle ($= 90^{\circ}$)};
\end{tikzpicture}
